import React, { useState, useEffect } from 'react';
import '../Sales.css';

function Sales() {
  const [sales, setSales] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const userRole = sessionStorage.getItem('userRole');

  useEffect(() => {
    fetchSales();
  }, []);

  const fetchSales = async () => {
    try {
      const token = sessionStorage.getItem(`token_${sessionStorage.getItem('tabId')}`);
      const endpoint = userRole === 'Admin' 
        ? 'http://localhost:5261/api/admin/sales'
        : 'http://localhost:5261/api/partner/sales';

      const response = await fetch(endpoint, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (!response.ok) throw new Error('Failed to fetch sales');

      const data = await response.json();
      setSales(data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching sales:', error);
      setError('Failed to load sales');
      setLoading(false);
    }
  };

  const updateCommissionPaymentStatus = async (saleId, newStatus) => {
    try {
      const token = sessionStorage.getItem(`token_${sessionStorage.getItem('tabId')}`);
      await fetch(`http://localhost:5261/api/admin/sales/${saleId}/commission-status`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ commissionPaymentStatus: newStatus })
      });
      fetchSales();
    } catch (error) {
      console.error('Error updating commission payment status:', error);
    }
  };

  const updateSalePaymentStatus = async (saleId, newStatus) => {
    try {
      const token = sessionStorage.getItem(`token_${sessionStorage.getItem('tabId')}`);
      const endpoint = userRole === 'Admin'
        ? `http://localhost:5261/api/admin/sales/${saleId}/sale-payment-status`
        : `http://localhost:5261/api/partner/sales/${saleId}/sale-payment-status`;

      await fetch(endpoint, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ salePaymentStatus: newStatus })
      });
      fetchSales();
    } catch (error) {
      console.error('Error updating sale payment status:', error);
    }
  };

  const getStatusClass = (status) => {
    switch (status?.toLowerCase()) {
      case 'completed':
      case 'paid':
        return 'status-completed';
      case 'pending':
        return 'status-pending';
      case 'cancelled':
      case 'failed':
        return 'status-cancelled';
      default:
        return '';
    }
  };

  if (loading) return <div className="loading">Loading sales...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="sales-container">
      <div className="sales-header">
        <h2>💰 Sales Management</h2>
        <p className="sales-subtitle">Track and manage all sales transactions</p>
      </div>

      {sales.length === 0 ? (
        <div className="no-data">
          <p>📊 No sales records found</p>
        </div>
      ) : (
        <div className="table-container">
          <table className="sales-table">
            <thead>
              <tr>
                <th>SALE ID</th>
                <th>PRODUCT</th>
                <th>PARTNER</th>
                <th>BUYER</th>
                <th>BUYER EMAIL</th>
                <th>AMOUNT</th>
                <th>COMMISSION</th>
                <th>SALE DATE</th>
                <th>SALE PAYMENT</th>
                <th>COMMISSION PAYMENT</th>
                <th>LICENSE KEY</th>
              </tr>
            </thead>
            <tbody>
              {sales.map((sale) => (
                <tr key={sale.saleId}>
                  <td>#{sale.saleId}</td>
                  <td>{sale.productName}</td>
                  <td>{sale.partnerName}</td>
                  <td>
                    <div>{sale.buyerName}</div>
                    {sale.buyerCompany && (
                      <div className="company-name">{sale.buyerCompany}</div>
                    )}
                  </td>
                  <td>{sale.buyerEmail}</td>
                  <td className="amount">₹{sale.saleAmount.toLocaleString()}</td>
                  <td className="commission">₹{sale.commissionAmount.toLocaleString()}</td>
                  <td>{new Date(sale.saleDate).toLocaleDateString()}</td>
                  <td>
                    {userRole === 'Admin' ? (
                      <select 
                        value={sale.salePaymentStatus}
                        onChange={(e) => updateSalePaymentStatus(sale.saleId, e.target.value)}
                        className={`status-select ${getStatusClass(sale.salePaymentStatus)}`}
                      >
                        <option value="Pending">Pending</option>
                        <option value="Paid">Paid</option>
                        <option value="Failed">Failed</option>
                      </select>
                    ) : (
                      <span className={`status-badge ${getStatusClass(sale.salePaymentStatus)}`}>
                        {sale.salePaymentStatus}
                      </span>
                    )}
                  </td>
                  <td>
                    {userRole === 'Admin' ? (
                      <select 
                        value={sale.commissionPaymentStatus}
                        onChange={(e) => updateCommissionPaymentStatus(sale.saleId, e.target.value)}
                        className={`status-select ${getStatusClass(sale.commissionPaymentStatus)}`}
                      >
                        <option value="Pending">Pending</option>
                        <option value="Completed">Completed</option>
                        <option value="Cancelled">Cancelled</option>
                      </select>
                    ) : (
                      <span className={`status-badge ${getStatusClass(sale.commissionPaymentStatus)}`}>
                        {sale.commissionPaymentStatus}
                      </span>
                    )}
                  </td>
                  <td className="license-key">
                    {sale.licenseKey || '-'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <div className="sales-summary">
        <div className="summary-card">
          <h4>Total Sales</h4>
          <p className="summary-value">{sales.length}</p>
        </div>
        <div className="summary-card">
          <h4>Total Revenue</h4>
          <p className="summary-value">
            ₹{sales.reduce((sum, sale) => sum + sale.saleAmount, 0).toLocaleString()}
          </p>
        </div>
        <div className="summary-card">
          <h4>Total Commission</h4>
          <p className="summary-value">
            ₹{sales.reduce((sum, sale) => sum + sale.commissionAmount, 0).toLocaleString()}
          </p>
        </div>
        <div className="summary-card">
          <h4>Paid Commissions</h4>
          <p className="summary-value">
            ₹{sales
              .filter(s => s.commissionPaymentStatus === 'Completed')
              .reduce((sum, sale) => sum + sale.commissionAmount, 0)
              .toLocaleString()}
          </p>
        </div>
      </div>
    </div>
  );
}

export default Sales;
